import { Request, Response } from "express";
import httpStatus from "http-status-codes";
import { catchAsync } from "../../utils/catchAsync";
import { sendResponse } from "../../utils/sendResponse";
import { EmbeddingService } from "./embedding.service";
import { IndexingService } from "./indexing.service";
import { LLMService } from "./llm.service";

const toPositiveNumber = (
  value: unknown,
  fallback: number,
  maximum: number,
) => {
  const parsed = Number(value);

  if (!Number.isFinite(parsed) || parsed <= 0) {
    return fallback;
  }

  return Math.min(parsed, maximum);
};

const toThreshold = (value: unknown, fallback = 0.4) => {
  const parsed = Number(value);

  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
    return fallback;
  }

  return parsed;
};

export class EmbeddingController {
  private static readonly embeddingService = new EmbeddingService();
  private static readonly indexingService = new IndexingService();
  private static readonly llmService = new LLMService();

  static getStats = catchAsync(async (_req: Request, res: Response) => {
    const result = await EmbeddingController.indexingService.getStats();

    sendResponse(res, {
      statusCode: httpStatus.OK,
      success: true,
      message: "Embedding stats retrieved successfully",
      data: result,
    });
  });

  static ingestProducts = catchAsync(async (_req: Request, res: Response) => {
    const result = await EmbeddingController.indexingService.indexProductsData();

    sendResponse(res, {
      statusCode: httpStatus.OK,
      success: true,
      message: result.message,
      data: result,
    });
  });

  static queryRag = catchAsync(async (req: Request, res: Response) => {
    const { query, limit, threshold, sourceType } = req.body as {
      query?: string;
      limit?: number;
      threshold?: number;
      sourceType?: string;
    };

    if (!query?.trim()) {
      throw new Error("Query is required");
    }

    const queryEmbedding =
      await EmbeddingController.embeddingService.generateEmbedding(query);

    const results = await EmbeddingController.indexingService.similaritySearch(
      queryEmbedding,
      toPositiveNumber(limit, 5, 10),
      toThreshold(threshold),
      sourceType?.trim() || "MEAL",
    );

    const context = results
      .map(
        (item, index) =>
          `${index + 1}. ${item.sourceLabel ?? item.sourceId}\n${item.content}`,
      )
      .join("\n\n");

    const systemPrompt = [
      "You are FoodHub's helpful food search assistant.",
      "Answer only from the provided context.",
      "If the context is empty or not enough, say that no matching meal was found.",
      "Keep the answer concise and practical.",
    ].join(" ");

    const answer = await EmbeddingController.llmService.generateResponse(
      systemPrompt,
      `User query: ${query}\n\nContext:\n${context || "No context found."}`,
    );

    sendResponse(res, {
      statusCode: httpStatus.OK,
      success: true,
      message: "RAG query completed successfully",
      data: {
        answer,
        matches: results,
      },
    });
  });
}
